# prompt_registry_client.py
import httpx, jinja2
from functools import lru_cache

REGISTRY_URL = "https://prompt-registry.internal"

@lru_cache(maxsize=256)
def _fetch_prompt(name: str, version: str) -> dict:
    resp = httpx.get(f"{REGISTRY_URL}/api/prompts/{name}/{version}",
                     headers={"Authorization": f"Bearer {get_service_token()}"})
    resp.raise_for_status()
    return resp.json()

class PromptRef:
    def __init__(self, name: str, version: str):
        self._spec = _fetch_prompt(name, version)

    def render(self, **variables) -> dict[str, str]:
        # Validate all required variables are provided
        for var in self._spec["variables"]:
            if var["required"] and var["name"] not in variables:
                raise ValueError(f"Missing required variable: {var['name']}")
            # Apply defaults for optional variables
            if not var["required"] and var["name"] not in variables:
                variables[var["name"]] = var.get("default", "")

        env = jinja2.Environment()
        return {
            "system": env.from_string(self._spec["system"]).render(**variables),
            "user":   env.from_string(self._spec["user"]).render(**variables),
        }

# Usage in a service:
RAG_PROMPT = PromptRef("rag-answer", "2.1.0")

async def answer_question(question: str, context: str) -> str:
    messages = RAG_PROMPT.render(question=question, context=context)
    response = await llm_client.complete(
        system=messages["system"],
        user=messages["user"],
        model="gpt-4o-mini",
    )
    return response.text
